    private static final char[] HEX_CHARSET = "0123456789abcdef".toCharArray();

    /**
     * Encrypts the provided byte array using AES-GCM with the given key.
     * Output hex string includes randomly generated nonce prepended to ciphertext + authentication tag,
     * which is required for decryption.
     *
     * @param key  Non-null, non-blank encryption key string (whitespace is preserved)
     * @param data Non-null byte array of data to encrypt
     * @return Lowercase hexadecimal string of encrypted payload (nonce + ciphertext + tag)
     * @throws IllegalArgumentException If input key is null/blank or data is null
     * @throws RuntimeException         If encryption fails due to cryptographic errors
     */
    public static String encrypt(String key, byte[] data) {
        // Input validation to prevent invalid operations
        if (key == null || key.trim().isEmpty()) {
            throw new IllegalArgumentException("Encryption key cannot be null or blank");
        }
        if (data == null) {
            throw new IllegalArgumentException("Data to encrypt cannot be null");
        }

        try {
            // Derive 128-bit AES key from input string using SHA-256 hashing
            // 128-bit AES is used for maximum compatibility with all Java 8+ distributions
            MessageDigest digest = MessageDigest.getInstance(KEY_DIGEST_ALGORITHM);
            byte[] keyHash = digest.digest(key.getBytes(StandardCharsets.UTF_8));
            byte[] aesKeyBytes = Arrays.copyOf(keyHash, 16);
            SecretKeySpec secretKey = new SecretKeySpec(aesKeyBytes, AES_ALGORITHM);

            // Generate cryptographically secure random nonce (must be unique per encryption with same key)
            SecureRandom secureRandom = new SecureRandom();
            byte[] nonce = new byte[GCM_NONCE_LENGTH];
            secureRandom.nextBytes(nonce);

            // Initialize AES-GCM cipher in encryption mode
            Cipher cipher = Cipher.getInstance(GCM_TRANSFORMATION);
            GCMParameterSpec gcmParams = new GCMParameterSpec(GCM_TAG_LENGTH_BITS, nonce);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey, gcmParams);

            // Perform encryption (result includes ciphertext + GCM authentication tag)
            byte[] ciphertextWithTag = cipher.doFinal(data);

            // Combine nonce and ciphertext (nonce is not secret, required for decryption)
            byte[] encryptedPayload = new byte[GCM_NONCE_LENGTH + ciphertextWithTag.length];
            System.arraycopy(nonce, 0, encryptedPayload, 0, GCM_NONCE_LENGTH);
            System.arraycopy(ciphertextWithTag, 0, encryptedPayload, GCM_NONCE_LENGTH, ciphertextWithTag.length);

            // Convert binary payload to hex string for easy transmission/storage
            return bytesToHex(encryptedPayload);
        } catch (Exception e) {
            // Wrap checked cryptographic exceptions into runtime exception for simpler caller handling
            throw new RuntimeException("AES encryption failed: " + e.getMessage(), e);
        }
    }

    /**
     * Efficiently converts a byte array to a lowercase hexadecimal string.
     *
     * @param bytes Input byte array to convert
     * @return Lowercase hexadecimal string representation
     */
    private static String bytesToHex(byte[] bytes) {
        char[] hexChars = new char[bytes.length * 2];
        for (int i = 0; i < bytes.length; i++) {
            int unsignedByte = bytes[i] & 0xFF;
            // Extract high nibble (first 4 bits) for first hex character
            hexChars[i * 2] = HEX_CHARSET[unsignedByte >>> 4];
            // Extract low nibble (last 4 bits) for second hex character
            hexChars[i * 2 + 1] = HEX_CHARSET[unsignedByte & 0x0F];
        }
        return new String(hexChars);
    }
}
